// Aggregate all data from parallel queries
let sightings = [];
let species = [];
let activity = [];

try { sightings = $('Get Recent Sightings').all().map(i => i.json); } catch(e) { sightings = []; }
try { species = $('Get Species Count').all().map(i => i.json); } catch(e) { species = []; }
try { activity = $('Get Hourly Activity').all().map(i => i.json); } catch(e) { activity = []; }

const userId = $('Webhook').first().json.body?.userId || 'anonymous';

return [{
  json: {
    recentSightings: sightings,
    speciesSummary: species,
    hourlyActivity: activity,
    userId: userId,
    hasData: sightings.length > 0 || species.length > 0 || activity.length > 0
  }
}];
